stylesheets.pagedjs-example.css:
@page {
  size: A5;
  margin: 20mm 18mm 22mm;
  @top-center {
    content: string(runningtitle);
    font: italic 9pt/1 Georgia, 'Times New Roman', serif;
    color: #8a7f72; letter-spacing: .03em; padding-bottom: 3mm;
  }
  @bottom-center {
    content: 'Page ' counter(page) ' of ' counter(pages);
    font: 9pt/1 Georgia, serif; color: #8a7f72; padding-top: 4mm;
  }
  @bottom-right {
    content: 'Field Notes'; font: 8pt/1 Georgia, serif; color: #b7ad9f;
  }
}
* { box-sizing: border-box; }
article { font-family: Georgia, 'Times New Roman', serif; color: #22201c; font-size: 11pt; line-height: 1.55; text-align: justify; hyphens: auto; -webkit-hyphens: auto; }
.title-block { text-align: left; margin-bottom: 8mm; }
.eyebrow { margin: 0; font-size: 8.5pt; letter-spacing: .22em; text-transform: uppercase; color: #b06a3b; }
h1 { string-set: runningtitle content(text); font-size: 22pt; line-height: 1.12; font-weight: 600; margin: 2mm 0 3mm; }
.byline { margin: 0; font-style: italic; font-size: 10pt; color: #6b645b; }
.lead { font-size: 12.5pt; color: #3a352e; text-align: left; }
p { margin: 0 0 3mm; }
.chapter { break-before: page; page-break-before: always; }
h2 { font-size: 15pt; font-weight: 600; color: #2b2822; margin: 0 0 3mm; padding-bottom: 2mm; border-bottom: 1px solid #ddd3c4; }
ul { margin: 3mm 0; padding-left: 6mm; }
li { margin: 0 0 1.5mm; }
